package main

import (
	"encoding/xml"
	"fmt"
)

type Config struct {
	XMLName xml.Name `xml:"config"`
	Settings  []Setting `xml:"setting"`
}

type Setting struct {
	Name  string `xml:"name,attr"`
	Value string `xml:"value,attr"`
}

func parseConfig(xmlData []byte) (Config, error) {
	var config Config
	err := xml.Unmarshal(xmlData, &config)
	if err != nil {
		return Config{}, fmt.Errorf("failed to parse XML: %w", err)
	}
	return config, nil
}

func main() {
	xmlData := []byte(`
	<config>
		<setting name="theme" value="dark"/>
		<setting name="language" value="en"/>
	</config>
	`)

	config, err := parseConfig(xmlData)
	if err != nil {
		fmt.Println("Error:", err)
		return
	}

	for _, setting := range config.Settings {
		fmt.Printf("Setting: %s=%s\n", setting.Name, setting.Value)
	}
}